DatabaseSetup.SQLCode:
-- Enable UUID extension CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
-- 1. Table: animes (Master Data) CREATE TABLE animes ( id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), title TEXT NOT NULL, slug TEXT UNIQUE NOT NULL, description TEXT, cover_url TEXT, status TEXT DEFAULT 'Ongoing', rating TEXT, source_origin TEXT, -- 'samehadaku' or 'anoboy' created_at TIMESTAMP WITH TIME ZONE DEFAULT now() );
-- 2. Table: episodes CREATE TABLE episodes ( id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), anime_id UUID REFERENCES animes(id) ON DELETE CASCADE, episode_no INT NOT NULL, title TEXT, created_at TIMESTAMP WITH TIME ZONE DEFAULT now() );
-- 3. Table: video_sources (Streaming Links) CREATE TABLE video_sources ( id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), episode_id UUID REFERENCES episodes(id) ON DELETE CASCADE, provider_name TEXT NOT NULL, video_url TEXT NOT NULL, quality TEXT DEFAULT '720p', is_embed BOOLEAN DEFAULT true );
-- Disable RLS bypass for Service Role (Internal) ALTER TABLE animes ENABLE ROW LEVEL SECURITY; CREATE POLICY "Enable Read for All" ON animes FOR SELECT USING (true);
